1	const basePremiumByItemType: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
9	const PROCESSING_FEE = 5;
10	
11	export const runScenario = (scenario: any): unknown => {
12	  const itemType = scenario.steps[0].items[0].type;
13	  const basePremium = basePremiumByItemType[itemType];
14	  const withSurcharge = Math.ceil(basePremium * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT) / 100);
15	  const premium = withSurcharge + PROCESSING_FEE;
16	  return { results: [{ premium }] };
17	};
